                <svg viewBox="0 0 18 18" fill="none" stroke-width="2" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><path d="M3.75 9h10.5M10.5 5.25 14.25 9l-3.75 3.75" stroke-linecap="round" stroke-linejoin="round"/></svg>
              </span>
              <span class="bload" aria-live="polite">
                <span class="spin" role="status" aria-label="Sending&#8230;"></span>
