                <svg viewBox="0 0 16 16" fill="none" stroke-width="1.5" xmlns="http://www.w3.org/2000/svg" aria-hidden="true"><path d="M8 1.5l5 2v4c0 3-2.5 5.5-5 6.5C5.5 13 3 10.5 3 7.5v-4l5-2z" stroke-linecap="round" stroke-linejoin="round"/></svg>
